import pandas as pd
policy = {"a": "required", "b": "optional"}
df = pd.DataFrame({"a": [1, None], "b": [None, 2]})
viol = {}
for col, pol in policy.items():
    if pol == 'required':
        n = int(df[col].isna().sum())
        if n:
            viol[col] = n
print(viol)
